export const TopMusicBar = ({ 
  playlistId, 
  onMenuClick,
  accessSettings,
  setAccessSettings
}: { 
  playlistId: string, 
  onMenuClick?: () => void,
  accessSettings?: any,
  setAccessSettings?: (s: any) => void
}) => {
  const [isExpanded, setIsExpanded] = useState(false); 
  const [mediaLoaded, setMediaLoaded] = useState(false); 
  const [showAccessMenu, setShowAccessMenu] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);

  // Pomodoro State
  const [timeLeft, setTimeLeft] = useState(25 * 60);
  const [isRunning, setIsRunning] = useState(false);
  const [mode, setMode] = useState<'focus' | 'break'>('focus');

  useEffect(() => {
    let interval: any;
    if (isRunning) {
      interval = setInterval(() => {
        setTimeLeft((prev) => {
          if (prev <= 1) {
            setIsRunning(false);
            return 0; 
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => {
        if(interval) clearInterval(interval);
    };
  }, [isRunning]);

  // Screen Reader Function (TTS)
  const toggleSpeech = () => {
    if (isSpeaking) {
      window.speechSynthesis.cancel();
      setIsSpeaking(false);
    } else {
      // Get visible text content from main area
      const mainContent = document.querySelector('main')?.innerText || "Sem conteúdo para ler.";
      const utterance = new SpeechSynthesisUtterance(mainContent);
      utterance.lang = 'pt-BR';
      utterance.rate = 1.1;
      utterance.onend = () => setIsSpeaking(false);
      window.speechSynthesis.speak(utterance);
      setIsSpeaking(true);
    }
  };

  const toggleTimer = () => setIsRunning(!isRunning);

  const resetTimer = () => {
    setIsRunning(false);
    setTimeLeft(mode === 'focus' ? 25 * 60 : 5 * 60);
  };

  const switchMode = () => {
    const newMode = mode === 'focus' ? 'break' : 'focus';
    setMode(newMode);
    setIsRunning(false);
    setTimeLeft(newMode === 'focus' ? 25 * 60 : 5 * 60);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs < 10 ? '0' : ''}${secs}`;
  };

  const toggleExpand = () => {
    if (!isExpanded && !mediaLoaded) {
      setMediaLoaded(true); 
    }
    setIsExpanded(!isExpanded);
  };

  const toggleAccessSetting = (key: string) => {
    if(setAccessSettings && accessSettings) {
        setAccessSettings({...accessSettings, [key]: !accessSettings[key]});
    }
  };

  const adjustFont = (delta: number) => {
    if(setAccessSettings && accessSettings) {
        setAccessSettings({...accessSettings, fontSize: Math.max(0.8, Math.min(1.5, accessSettings.fontSize + delta))});
    }
  };

  return (
    <div className="w-full bg-slate-900 border-b border-slate-800 flex flex-col shrink-0 transition-all duration-300 ease-in-out relative z-30">
      <div className="flex items-center justify-between px-4 py-2 bg-slate-800 text-white h-14 shadow-md relative">

        {/* Left: Title & Mobile Menu */}
        <div className="flex items-center gap-2 z-10">
          <button onClick={onMenuClick} className="md:hidden mr-2 text-slate-400 hover:text-white" aria-label="Abrir menu">
            <Menu size={20} />
          </button>
          <div className="flex items-center gap-2 text-sm font-bold text-teal-400">
             <Music size={16} className={isRunning ? "animate-pulse" : ""} aria-hidden="true" />
             <span className="hidden sm:inline">Zona de Foco</span>
          </div>
        </div>

        {/* Center: Pomodoro Control */}
        <div className="absolute left-1/2 -translate-x-1/2 top-1/2 -translate-y-1/2 flex items-center gap-3 bg-slate-900/80 px-4 py-1.5 rounded-full border border-slate-700 shadow-inner backdrop-blur-sm z-20">
          <button 
            onClick={switchMode} 
            className={`transition hover:scale-110 ${mode === 'focus' ? 'text-teal-400' : 'text-blue-400'}`}
            title={mode === 'focus' ? "Modo Foco (25m)" : "Modo Pausa (5m)"}
            aria-label={mode === 'focus' ? "Alternar para Pausa" : "Alternar para Foco"}
          >
            {mode === 'focus' ? <Brain size={16} aria-hidden="true"/> : <Coffee size={16} aria-hidden="true"/>}
          </button>

          <span className={`font-mono font-bold text-lg w-16 text-center ${mode === 'focus' ? 'text-white' : 'text-blue-200'}`} role="timer" aria-label={`Tempo restante: ${formatTime(timeLeft)}`}>
            {formatTime(timeLeft)}
          </span>

          <div className="h-4 w-px bg-slate-600 mx-1" aria-hidden="true"></div>

          <button onClick={toggleTimer} className="hover:text-teal-400 transition" aria-label={isRunning ? "Pausar temporizador" : "Iniciar temporizador"}>
            {isRunning ? <Pause size={16} fill="currentColor" /> : <Play size={16} fill="currentColor" />}
          </button>

          <button onClick={resetTimer} className="text-slate-500 hover:text-white transition" title="Reiniciar" aria-label="Reiniciar temporizador">
            <RotateCcw size={14} />
          </button>
        </div>

        {/* Right: Accessibility & Expand */}
        <div className="flex items-center gap-3 z-10">
            <div className="relative">
                <button 
                    onClick={() => setShowAccessMenu(!showAccessMenu)}
                    className={`transition hover:text-white ${showAccessMenu || accessSettings?.mask || accessSettings?.dyslexic ? 'text-yellow-400' : 'text-slate-400'}`}
