                                </div>
                            </div>

                            <button onClick={() => toggleAccessSetting('dyslexic')} className="w-full flex justify-between items-center text-sm p-2 rounded hover:bg-slate-700 transition">
                                <span className="flex items-center gap-2"><Type size={16}/> Fonte Dislexia</span>
                                <div className={`w-8 h-4 rounded-full relative transition ${accessSettings?.dyslexic ? 'bg-teal-500' : 'bg-slate-600'}`} aria-hidden="true">
                                    <div className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition-all ${accessSettings?.dyslexic ? 'left-4.5' : 'left-0.5'}`} style={{left: accessSettings?.dyslexic ? '18px' : '2px'}}></div>
                                </div>
                            </button>

                            <button onClick={() => toggleAccessSetting('mask')} className="w-full flex justify-between items-center text-sm p-2 rounded hover:bg-slate-700 transition">
                                <span className="flex items-center gap-2"><MoveHorizontal size={16}/> Régua de Leitura</span>
                                <div className={`w-8 h-4 rounded-full relative transition ${accessSettings?.mask ? 'bg-teal-500' : 'bg-slate-600'}`} aria-hidden="true">
                                    <div className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition-all`} style={{left: accessSettings?.mask ? '18px' : '2px'}}></div>
                                </div>
                            </button>

                            <button onClick={() => toggleAccessSetting('reducedMotion')} className="w-full flex justify-between items-center text-sm p-2 rounded hover:bg-slate-700 transition">
                                <span className="flex items-center gap-2"><Move size={16}/> Reduzir Movimento</span>
                                <div className={`w-8 h-4 rounded-full relative transition ${accessSettings?.reducedMotion ? 'bg-teal-500' : 'bg-slate-600'}`} aria-hidden="true">
                                    <div className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition-all`} style={{left: accessSettings?.reducedMotion ? '18px' : '2px'}}></div>
                                </div>
                            </button>

                            <div className="border-t border-slate-700 my-2"></div>

                            {/* Novas Opções para Cegos e Surdos */}

