export const FlashcardView = ({ addXp, notify }: any) => {
  const [topic, setTopic] = useState('');
  const [cards, setCards] = useState<Flashcard[]>([]);
  const [loading, setLoading] = useState(false);
  const [flippedIndex, setFlippedIndex] = useState<number | null>(null);
  const [studyMode, setStudyMode] = useState(false);
  const [currentCardIndex, setCurrentCardIndex] = useState(0);

  const generateCards = async () => {
    if (!topic) return;
    setLoading(true);
    const prompt = `Crie 5 flashcards sobre "${topic}". Retorne APENAS um JSON array: [{"front": "Pergunta", "back": "Resposta"}].`;

    try {
        const result = await callGeminiJSON<Flashcard[]>(prompt);
        if (result && Array.isArray(result)) {
            setCards(result);
            notify("Flashcards gerados!", "success");
            addXp(20);
            setStudyMode(false);
        } else {
            notify("Erro ao gerar cards.", "error");
        }
    } catch (e) {
        notify("Erro na IA.", "error");
    } finally {
        setLoading(false);
    }
  };

  const handleStudyNext = (difficulty: 'easy' | 'medium' | 'hard') => {
      // Simulação de algoritmo SRS (Spaced Repetition)
      let xpGain = 0;
      if (difficulty === 'hard') xpGain = 10;
      if (difficulty === 'medium') xpGain = 5;
      if (difficulty === 'easy') xpGain = 2;

      addXp(xpGain);
      setFlippedIndex(null);

      if (currentCardIndex < cards.length - 1) {
          setTimeout(() => setCurrentCardIndex(curr => curr + 1), 300);
      } else {
          notify("Sessão de estudo concluída!", "success");
          setStudyMode(false);
          setCurrentCardIndex(0);
      }
  };

  return (
    <div className="space-y-6 max-w-4xl mx-auto animate-fadeIn">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <h2 className="text-2xl font-bold text-slate-800 mb-4 flex items-center gap-2"><Layers className="text-blue-600"/> Gerador de Flashcards</h2>
        <div className="flex gap-2">
          <input 
            value={topic}
            onChange={(e) => setTopic(e.target.value)}
            placeholder="Ex: Revolução Francesa, Verbos em Inglês..."
            className="flex-1 p-3 border rounded-xl bg-slate-50 focus:ring-2 focus:ring-blue-500 outline-none"
          />
          <button 
            onClick={generateCards}
            disabled={loading || !topic}
            className="bg-blue-600 text-white px-6 py-3 rounded-xl hover:bg-blue-700 disabled:opacity-50 font-bold flex items-center gap-2"
          >
            {loading ? <Loader2 className="animate-spin"/> : <Sparkles size={20}/>}
            Gerar
          </button>
        </div>
      </div>

      {cards.length > 0 && !studyMode && (
          <div className="flex justify-between items-center">
              <h3 className="font-bold text-slate-500 uppercase tracking-wider">{cards.length} Cartões Criados</h3>
              <button onClick={() => setStudyMode(true)} className="bg-teal-500 text-white px-6 py-2 rounded-full font-bold hover:bg-teal-600 shadow-md transition transform hover:scale-105 flex items-center gap-2">
                  <Play size={18} fill="currentColor"/> Modo Estudo
              </button>
          </div>
      )}

      {/* Grid View */}
      {cards.length > 0 && !studyMode && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {cards.map((card, i) => (
            <div 
              key={i}
              className="group h-48 perspective-1000 cursor-pointer"
              onClick={() => setFlippedIndex(flippedIndex === i ? null : i)}
            >
              <div className={`relative w-full h-full transition-transform duration-500 transform-style-3d ${flippedIndex === i ? 'rotate-y-180' : ''}`}>
                <div className="absolute inset-0 backface-hidden bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex items-center justify-center text-center hover:border-blue-400 transition">
                  <p className="font-medium text-slate-700">{card.front}</p>
                  <div className="absolute top-3 right-3 text-slate-300"><HelpCircleIcon size={16}/></div>
                </div>
                <div className="absolute inset-0 backface-hidden rotate-y-180 bg-blue-50 p-6 rounded-xl border border-blue-200 shadow-sm flex items-center justify-center text-center">
                  <p className="font-bold text-blue-800">{card.back}</p>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Study Mode View */}
      {studyMode && cards.length > 0 && (
          <div className="flex flex-col items-center justify-center py-10">
              <div className="w-full max-w-md h-80 perspective-1000 cursor-pointer mb-8" onClick={() => setFlippedIndex(flippedIndex === currentCardIndex ? null : currentCardIndex)}>
                  <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${flippedIndex === currentCardIndex ? 'rotate-y-180' : ''}`}>
                      <div className="absolute inset-0 backface-hidden bg-white rounded-3xl shadow-2xl flex flex-col items-center justify-center p-8 border-2 border-slate-100">
