export const TransformerUploadView = ({ user, addXp, notify }: any) => {
  const [text, setText] = useState('');
  const [generatedScript, setGeneratedScript] = useState<PodcastLine[] | null>(null);
  const [loading, setLoading] = useState(false);
  const [audioLoading, setAudioLoading] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);

  // Audio Controls
  const [isPlaying, setIsPlaying] = useState(false);
  const [isPaused, setIsPaused] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const sourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const startTimeRef = useRef<number>(0);
  const pauseTimeRef = useRef<number>(0);
  const audioBufferRef = useRef<AudioBuffer | null>(null);

  const generateScript = async () => {
    if (!text) return;
    setLoading(true);
    setAudioUrl(null);
    setGeneratedScript(null);
    stopAudio(); // Reset audio state

    const instruction = "Você é um roteirista de podcast educativo. Crie um diálogo natural entre dois apresentadores: Alex (Curioso) e Bia (Especialista). Use linguagem falada, dinâmica e inclusiva.";
    const prompt = `Transforme este texto em um roteiro de podcast curto (max 10 falas).
    Texto base: "${text}"

    Retorne ESTRITAMENTE um JSON Array neste formato:
    [
      {"speaker": "Alex", "text": "Fala do Alex..."},
      {"speaker": "Bia", "text": "Fala da Bia..."}
    ]
    `;

    const result = await callGeminiJSON<PodcastLine[]>(prompt, instruction);
    if (result && Array.isArray(result)) {
        // Sanitizar oradores
        const sanitized = result.map(l => ({
            speaker: l.speaker.includes("Alex") ? "Alex" : "Bia", // Força nomes exatos para o modelo de áudio
            text: l.text
        }));
        setGeneratedScript(sanitized);
        addXp(15);
    } else {
        notify("Erro ao criar roteiro. Tente novamente.", "error");
    }
    setLoading(false);
  };

  const generateAudio = async () => {
      if (!generatedScript) return;
      setAudioLoading(true);
      try {
          const audioBase64 = await generateNeuralAudio(generatedScript);
          if (audioBase64) {
              // Convert PCM to WAV for browser compatibility
              const pcmData = decodeBase64Audio(audioBase64);
              const wavBuffer = pcmToWav(pcmData);
              const blob = new Blob([wavBuffer], { type: 'audio/wav' });
              const url = URL.createObjectURL(blob);
              setAudioUrl(url);
              notify("Podcast gerado com sucesso!", "success");
              addXp(50);
          } else {
              throw new Error("No audio data returned");
          }
      } catch (e) {
          console.error(e);
          notify("Erro ao gerar áudio neural.", "error");
      } finally {
          setAudioLoading(false);
      }
  };

  const initAudio = async () => {
      if (!audioUrl) return;

      // Se estiver pausado, apenas retoma
      if (isPaused && audioContextRef.current?.state === 'suspended') {
          await audioContextRef.current.resume();
          setIsPaused(false);
          setIsPlaying(true);
          return;
      }

      // Se já estiver tocando, não faz nada
      if (isPlaying) return;

      try {
          const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
          audioContextRef.current = ctx;

          const response = await fetch(audioUrl);
          const arrayBuffer = await response.arrayBuffer();
          const decodedBuffer = await ctx.decodeAudioData(arrayBuffer);
          audioBufferRef.current = decodedBuffer;

          playBuffer(decodedBuffer, ctx);
      } catch (e) {
          console.error("Playback error:", e);
          notify("Erro ao reproduzir áudio.", "error");
      }
  };

  const playBuffer = (buffer: AudioBuffer, ctx: AudioContext, offset: number = 0) => {
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.start(0, offset);

      sourceNodeRef.current = source;
      startTimeRef.current = ctx.currentTime - offset;
      setIsPlaying(true);
      setIsPaused(false);

      source.onended = () => {
          // Só reseta se não foi pausado manualmente
          if (ctx.state === 'running') {
            setIsPlaying(false);
            setIsPaused(false);
          }
      };
  };

  const pauseAudio = async () => {
      if (audioContextRef.current && isPlaying) {
          await audioContextRef.current.suspend();
          setIsPaused(true);
          setIsPlaying(false);
      }
  };

  const stopAudio = () => {
      if (sourceNodeRef.current) {
          sourceNodeRef.current.stop();
          sourceNodeRef.current = null;
      }
      if (audioContextRef.current) {
          audioContextRef.current.close();
          audioContextRef.current = null;
      }
      setIsPlaying(false);
      setIsPaused(false);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-fadeIn">
        <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center gap-3 mb-6">
                <div className="bg-purple-100 p-3 rounded-xl text-purple-600"><UploadCloud size={32}/></div>
                <div>
                    <h2 className="text-2xl font-bold text-slate-800">AdaptCast Studio</h2>
                    <p className="text-slate-500">Transforme textos em Podcasts com vozes neurais (Alex & Bia).</p>
                </div>
            </div>

            <textarea
                value={text}
                onChange={(e) => setText(e.target.value)}
                placeholder="Cole seu texto, resumo ou anotações aqui..."
                className="w-full h-40 p-4 border rounded-xl bg-slate-50 focus:ring-2 focus:ring-purple-500 outline-none resize-none mb-4"
            />

            <div className="flex justify-end">
                <button 
                    onClick={generateScript}
                    disabled={loading || !text}
                    className="bg-purple-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-purple-700 disabled:opacity-50 flex items-center gap-2"
                >
