export const CognitiveTestView = ({ user, setUser, setActiveView, addXp, notify }: any) => {
  const [step, setStep] = useState(0); // 0 = Intro, 1..5 = Questions, 6 = Analyzing
  const [answers, setAnswers] = useState<number[]>([]);

  // Fase 0: Introdução
  if (step === 0) {
      return (
        <div className="max-w-3xl mx-auto py-10 animate-fadeIn">
            {user.cognitiveProfile && (
                <div className="mb-8 bg-white border border-slate-200 rounded-2xl p-6 shadow-sm flex items-center justify-between">
                    <div>
                        <h4 className="font-bold text-slate-500 uppercase text-xs mb-1">Resultado Atual</h4>
                        <div className="flex items-center gap-2">
                             <h3 className="text-2xl font-bold text-indigo-700">{user.cognitiveProfile.split(':')[1]}</h3>
                             {user.archetype && <span className="bg-indigo-100 text-indigo-700 px-2 py-1 rounded text-xs font-bold">{user.archetype}</span>}
                        </div>
                    </div>
                    <button onClick={() => setActiveView('dashboard')} className="text-slate-400 hover:text-slate-600">Voltar</button>
                </div>
            )}

            <div className="bg-white rounded-3xl shadow-xl overflow-hidden text-center p-12 border border-slate-100 relative">
                <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-teal-400 to-blue-500"></div>
                <BrainCircuit size={80} className="mx-auto text-teal-500 mb-6 animate-pulse" />
                <h2 className="text-4xl font-bold text-slate-800 mb-4">Mapeamento Neural</h2>
                <p className="text-slate-600 text-lg mb-8 max-w-lg mx-auto leading-relaxed">
                    Vamos calibrar a IA para funcionar exatamente como seu cérebro. 
                    Responda 5 perguntas rápidas para descobrirmos seu <strong>Arquétipo de Aprendizagem</strong>.
                </p>
                <button 
                    onClick={() => setStep(1)} 
                    className="bg-teal-600 text-white text-xl font-bold px-10 py-4 rounded-full hover:bg-teal-700 hover:scale-105 transition shadow-lg flex items-center gap-3 mx-auto"
                >
                    Iniciar Calibragem <ArrowRight />
                </button>
            </div>
        </div>
      );
  }

  // Fase de Análise (Fake Loading)
  if (step === 6) {
      setTimeout(() => calculateResult(), 3000); // 3 segundos de suspense
      return (
          <div className="h-full flex flex-col items-center justify-center animate-fadeIn">
              <div className="relative w-32 h-32 mb-8">
                  <div className="absolute inset-0 border-4 border-slate-200 rounded-full"></div>
                  <div className="absolute inset-0 border-4 border-teal-500 rounded-full border-t-transparent animate-spin"></div>
                  <Brain className="absolute inset-0 m-auto text-teal-600" size={48} />
              </div>
              <h3 className="text-2xl font-bold text-slate-800 mb-2">Analisando Padrões Neurais...</h3>
              <p className="text-slate-500">Construindo seu Neuro-ID exclusivo.</p>
          </div>
      );
  }

  const handleAnswer = (optionIndex: number) => {
    const newAnswers = [...answers, optionIndex];
    setAnswers(newAnswers);
    if (step < COGNITIVE_QUESTIONS.length) {
      setStep(step + 1);
    } else {
      setStep(6); // Vai para análise
    }
  };

  const calculateResult = () => {
    // Lógica Combinatória para Arquétipos
    // Q1 (Estilo): 0=Visual, 1=Auditivo, 2=Cinestésico, 3=Leitor, 4=Multimodal
    // Q3 (Foco): 0=Hiperfoco, 1=Dinâmico, 2=Social, 3=Curto, 4=Pressão

    const styleIdx = answers[0];
    const focusIdx = answers[2];

    const styles = ["Visual", "Auditivo", "Cinestésico", "Leitor/Lógico", "Multimodal"];
    const focuses = ["Imersivo", "Dinâmico", "Social", "Ágil", "Intenso"]; // Adjetivos para o Arquétipo

    const baseProfile = styles[styleIdx];
    const archetype = `Visionário ${focuses[focusIdx]}`; // Exemplo simplificado, ideal seria uma matriz completa

    // Matriz de Nomes Criativos
    let archetypeName = "Explorador Nato";
    if (styleIdx === 0 && focusIdx === 0) archetypeName = "Visionário Imersivo";
    if (styleIdx === 1 && focusIdx === 2) archetypeName = "Comunicador Social";
    if (styleIdx === 2 && focusIdx === 1) archetypeName = "Construtor Ágil";
    if (styleIdx === 3 && focusIdx === 0) archetypeName = "Arquiteto Lógico";
    if (styleIdx === 4 && focusIdx === 4) archetypeName = "Polímata Intenso";
    // ... (fallback para combinações genéricas)
    if (!archetypeName) archetypeName = `${styles[styleIdx].split('/')[0]} ${focuses[focusIdx]}`;

    const profileString = `Predominância: ${baseProfile}`;

    // Salvar
    const updatedUser = { ...user, cognitiveProfile: profileString, archetype: archetypeName };
    setUser(updatedUser);
    localStorage.setItem('adaptmind_cognitive_profile', profileString);
    localStorage.setItem('adaptmind_archetype', archetypeName);

    addXp(100);
    notify("Perfil Calibrado com Sucesso!", "success");
    setActiveView('dashboard'); // Volta pro Dashboard para ver o resultado lindo
  };

  const currentQuestion = COGNITIVE_QUESTIONS[step - 1];

  return (
    <div className="max-w-2xl mx-auto py-10 px-4 animate-slideIn">
      <div className="mb-8 flex justify-between items-center">
          <span className="text-sm font-bold text-slate-400 uppercase tracking-widest">Pergunta {step} de 5</span>
          <div className="w-1/3 h-2 bg-slate-200 rounded-full overflow-hidden">
              <div className="h-full bg-teal-500 transition-all duration-500" style={{ width: `${(step / 5) * 100}%` }}></div>
          </div>
      </div>

      <h2 className="text-3xl font-bold text-slate-800 mb-8 leading-tight">{currentQuestion.text}</h2>

      <div className="space-y-4">
        {currentQuestion.options.map((opt: any, index: number) => (
          <button
            key={index}
            onClick={() => handleAnswer(index)}
            className="w-full text-left p-5 rounded-xl border-2 border-slate-100 hover:border-teal-500 hover:bg-teal-50 transition-all duration-200 flex items-center gap-4 group bg-white"
          >
            <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 group-hover:bg-teal-500 group-hover:text-white transition-colors">
                <opt.icon size={20} />
            </div>
            <span className="text-lg font-medium text-slate-700 group-hover:text-teal-900">{opt.text}</span>
          </button>
        ))}
      </div>
    </div>
  );
};

export const AdminView = ({ 
  user, notify, playlistId, setPlaylistId, 
  agentPrompts, updateAgentPrompt, 
  agentKnowledge, updateAgentKnowledge, 
  theme, setTheme,
  team, setTeam,
  users, setUsers,
  customLogo, setCustomLogo 
}: any) => {
  const [activeTab, setActiveTab] = useState<'general' | 'team' | 'ai' | 'users'>('general');

  // --- LOGO UPLOAD LOGIC ---
  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      // Validação de Tamanho (2MB)
      if (file.size > 2 * 1024 * 1024) {
          notify("Arquivo muito grande. Máx 2MB.", "error");
          return;
      }

      const reader = new FileReader();
      reader.onload = (ev) => {
          const img = new Image();
          img.src = ev.target?.result as string;
          img.onload = () => {
              // COMPRESSÃO AUTOMÁTICA
              const canvas = document.createElement('canvas');
              const ctx = canvas.getContext('2d');
              const maxSize = 150; // Tamanho ideal para ícone
              let width = img.width;
              let height = img.height;

              if (width > height) {
                  if (width > maxSize) {
                      height *= maxSize / width;
                      width = maxSize;
                  }
              } else {
                  if (height > maxSize) {
                      width *= maxSize / height;
                      height = maxSize;
                  }
              }
              canvas.width = width;
              canvas.height = height;
              ctx?.drawImage(img, 0, 0, width, height);

              // Salvar como PNG para manter transparência
              const compressedBase64 = canvas.toDataURL('image/png');

              setCustomLogo(compressedBase64);
              localStorage.setItem('adaptmind_logo', compressedBase64);
              notify("Logo atualizado com sucesso!", "success");

              // Limpar input para permitir re-upload do mesmo arquivo se necessário
              e.target.value = '';
          };
      };
      reader.readAsDataURL(file);
  };

  const removeLogo = () => {
      setCustomLogo("");
      localStorage.removeItem('adaptmind_logo');
      notify("Logo removido. Usando padrão.", "info");
  };

  // --- TEAM CRUD LOGIC ---
  const [isAddingMember, setIsAddingMember] = useState(false);
  const [newMember, setNewMember] = useState<Omit<TeamMember, 'id'>>({ name: '', role: '', desc: '' });

  const addMember = () => {
      if (!newMember.name || !newMember.role) return;
      setTeam([...team, { ...newMember, id: Date.now() }]);
      setIsAddingMember(false);
      setNewMember({ name: '', role: '', desc: '' });
      notify("Membro adicionado!", "success");
  };

  const removeMember = (id: number) => {
      setTeam(team.filter((m: any) => m.id !== id));
      notify("Membro removido.", "info");
  };

  if (user.role !== 'admin') return <div className="text-center p-10 text-red-500 font-bold">Acesso Negado</div>;

  return (
    <div className="max-w-4xl mx-auto animate-fadeIn">
      <h2 className="text-3xl font-bold text-slate-800 mb-6 flex items-center gap-3">
        <Settings size={32} className="text-purple-600" /> Painel Administrativo
      </h2>

      {/* Tabs */}
      <div className="flex gap-2 mb-6 border-b border-slate-200">
          <button onClick={() => setActiveTab('general')} className={`px-4 py-2 font-bold border-b-2 transition ${activeTab === 'general' ? 'border-purple-600 text-purple-600' : 'border-transparent text-slate-500'}`}>Geral</button>
          <button onClick={() => setActiveTab('team')} className={`px-4 py-2 font-bold border-b-2 transition ${activeTab === 'team' ? 'border-purple-600 text-purple-600' : 'border-transparent text-slate-500'}`}>Equipe</button>
          <button onClick={() => setActiveTab('ai')} className={`px-4 py-2 font-bold border-b-2 transition ${activeTab === 'ai' ? 'border-purple-600 text-purple-600' : 'border-transparent text-slate-500'}`}>Treinamento IA</button>
          <button onClick={() => setActiveTab('users')} className={`px-4 py-2 font-bold border-b-2 transition ${activeTab === 'users' ? 'border-purple-600 text-purple-600' : 'border-transparent text-slate-500'}`}>Usuários</button>
      </div>

      {activeTab === 'general' && (
          <div className="space-y-6">
              {/* Logo Upload Section */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                  <h3 className="font-bold text-slate-700 mb-4 flex items-center gap-2"><ImageIcon size={20}/> Logo Personalizado</h3>
                  <div className="flex items-center gap-6">
                      <div className="w-24 h-24 bg-[url('https://www.transparenttextures.com/patterns/checkerboard.png')] bg-slate-100 rounded-xl flex items-center justify-center border border-slate-300 overflow-hidden relative">
                          {customLogo ? (
                              <img src={customLogo} alt="Preview" className="w-full h-full object-contain" />
                          ) : (
                              <span className="text-xs text-slate-400 font-bold">Padrão</span>
                          )}
                      </div>
                      <div className="space-y-2">
                          <label className="bg-purple-600 text-white px-4 py-2 rounded-lg font-bold hover:bg-purple-700 cursor-pointer inline-flex items-center gap-2">
                              <UploadCloud size={18}/> Carregar Imagem
                              <input type="file" accept="image/*" className="hidden" onChange={handleLogoUpload} />
                          </label>
                          <p className="text-xs text-slate-400">Recomendado: PNG Transparente (Nós comprimimos auto)</p>
