                      </div>
                  </div>
              </div>

              {/* Theme Selector */}
              <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
                  <h3 className="font-bold text-slate-700 mb-4 flex items-center gap-2"><Layout size={20}/> Tema da Interface</h3>
                  <div className="flex gap-4">
                      <button onClick={() => setTheme('light')} className={`flex-1 p-4 rounded-xl border-2 flex flex-col items-center gap-2 ${theme === 'light' ? 'border-purple-500 bg-purple-50' : 'border-slate-100'}`}>
