                          <span className="font-bold text-sm">Escuro</span>
                      </button>
                      <button onClick={() => setTheme('high-contrast')} className={`flex-1 p-4 rounded-xl border-2 flex flex-col items-center gap-2 ${theme === 'high-contrast' ? 'border-yellow-400 bg-black text-yellow-400' : 'border-slate-100 bg-black text-slate-500'}`}>
                          <div className="w-full h-4 bg-black border border-white rounded"></div>
                          <span className="font-bold text-sm">Alto Contraste</span>
                      </button>
                  </div>
